// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./PRCToken.sol";

/// @title CorporateVault
/// @notice Manages corporate buyer registration, PRC purchases, retirements,
///         and the protocol payment pool that funds collector HBAR payouts.
///         Protocol split (per spec §12.1):
///           - 50% of PRC revenue → payment pool (collector payouts)
///           - 13.5% → protocol treasury
///           - 36.5% → payment pool reserve buffer
contract CorporateVault {
    struct CorporateBuyer {
        address walletAddress;
        string companyName;
        string industry;
        string contactEmail;
        string registrationNumber;
        uint256 totalPrcsOwned;
        uint256 totalPrcsRetired;
        uint256 totalHbarSpent;
        uint256 collectorsSupported;
        bool isActive;
        uint256 registeredAt;
    }

    mapping(address => CorporateBuyer) public corporateBuyers;
    address[] public buyerAddresses;

    PRCToken public prcToken;
    address public admin;
    address public recoveryAgent;

    uint256 public constant REGISTRATION_FEE = 50 ether;    // 50 HBAR one-time
    uint256 public constant DEFAULT_PRC_PRICE = 1.1 ether;  // 1.1 HBAR per PRC (average)
    uint256 public constant POOL_SHARE_BPS    = 8650;        // 86.5% to payment pool reserve
    uint256 public constant TREASURY_SHARE_BPS = 1350;       // 13.5% to treasury

    uint256 public paymentPool;   // HBAR available to pay collectors
    uint256 public treasury;      // Protocol treasury balance

    event CorporateBuyerRegistered(
        address indexed buyerAddress,
        string companyName,
        string industry
    );

    event PRCPurchased(
        address indexed buyer,
        string companyName,
        uint256 prcsBought,
        uint256 hbarPaid
    );

    event PaymentPoolDeposit(uint256 amount);
    event CollectorPaid(address indexed collector, uint256 amount, string attestationId);

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    modifier onlyAdminOrAgent() {
        require(msg.sender == admin || msg.sender == recoveryAgent, "Not authorized");
        _;
    }

    constructor(address _prcToken) {
        prcToken = PRCToken(_prcToken);
        admin = msg.sender;
    }

    function setRecoveryAgent(address _agent) external onlyAdmin {
        recoveryAgent = _agent;
    }

    function registerCorporateBuyer(
        string memory _companyName,
        string memory _industry,
        string memory _contactEmail,
        string memory _registrationNumber
    ) external payable {
        require(corporateBuyers[msg.sender].walletAddress == address(0), "Already registered");
        require(msg.value >= REGISTRATION_FEE, "Insufficient registration fee");

        corporateBuyers[msg.sender] = CorporateBuyer({
            walletAddress: msg.sender,
            companyName: _companyName,
            industry: _industry,
            contactEmail: _contactEmail,
            registrationNumber: _registrationNumber,
            totalPrcsOwned: 0,
            totalPrcsRetired: 0,
            totalHbarSpent: 0,
            collectorsSupported: 0,
            isActive: true,
            registeredAt: block.timestamp
        });

        // Registration fee goes to treasury
        treasury += msg.value;
        buyerAddresses.push(msg.sender);
        emit CorporateBuyerRegistered(msg.sender, _companyName, _industry);
    }

    function purchasePRCs(uint256 _prcAmount) external payable {
        require(corporateBuyers[msg.sender].isActive, "Buyer not registered");
        require(_prcAmount > 0, "Invalid amount");

        uint256 totalPrice = (_prcAmount * DEFAULT_PRC_PRICE) / 1000; // /1000 because PRC has 3 decimals (gram granularity)
        require(msg.value >= totalPrice, "Insufficient payment");

        // Transfer PRCs from vault to buyer
        prcToken.transfer(msg.sender, _prcAmount);

        // Split revenue: 86.5% to payment pool, 13.5% to treasury
        uint256 toTreasury = (msg.value * TREASURY_SHARE_BPS) / 10000;
        uint256 toPool     = msg.value - toTreasury;

        paymentPool += toPool;
        treasury    += toTreasury;

        corporateBuyers[msg.sender].totalPrcsOwned  += _prcAmount;
        corporateBuyers[msg.sender].totalHbarSpent  += msg.value;

        emit PRCPurchased(msg.sender, corporateBuyers[msg.sender].companyName, _prcAmount, msg.value);
        emit PaymentPoolDeposit(toPool);
    }

    function retirePRCs(uint256 _amount, string memory _reportRef) external {
        require(corporateBuyers[msg.sender].isActive, "Buyer not registered");
        require(prcToken.getBalance(msg.sender) >= _amount, "Insufficient PRCs");

        prcToken.retire(_amount, corporateBuyers[msg.sender].companyName, _reportRef);

        corporateBuyers[msg.sender].totalPrcsOwned   -= _amount;
        corporateBuyers[msg.sender].totalPrcsRetired += _amount;
    }

    /// @notice Called by Recovery Agent to pay a collector after attestation verification.
    /// @dev In production this triggers a Hedera Scheduled Transaction; this function
    ///      records the pool deduction and emits the audit event.
    function triggerCollectorPayment(
        address _collector,
        uint256 _amountTinybar,
        string calldata _attestationId
    ) external onlyAdminOrAgent {
        require(paymentPool >= _amountTinybar, "Insufficient pool balance");
        paymentPool -= _amountTinybar;

        // In Hedera EVM, native token transfers use: payable(_collector).transfer(...)
        // For testnet demo, the actual transfer uses Hedera Scheduled Transactions off-chain.
        payable(_collector).transfer(_amountTinybar);

        emit CollectorPaid(_collector, _amountTinybar, _attestationId);
    }

    function getPaymentPoolBalance() external view returns (uint256) {
        return paymentPool;
    }

    function getTreasuryBalance() external view returns (uint256) {
        return treasury;
    }

    function getCorporateBuyer(address _buyer) external view returns (CorporateBuyer memory) {
        return corporateBuyers[_buyer];
    }

    function getBuyerCount() external view returns (uint256) {
        return buyerAddresses.length;
    }

    /// @notice Check payment pool health. Healthy = pool covers 30+ days of payouts.
    function checkPaymentPoolHealth(uint256 _dailyPayoutEstimate)
        external view returns (bool isHealthy, uint256 daysRemaining)
    {
        if (_dailyPayoutEstimate == 0) return (true, type(uint256).max);
        daysRemaining = paymentPool / _dailyPayoutEstimate;
        isHealthy     = daysRemaining >= 30;
    }

    receive() external payable {
        paymentPool += msg.value;
        emit PaymentPoolDeposit(msg.value);
    }
}

src/PRCToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./CollectorRegistry.sol";
import "./StationRegistry.sol";

/// @title PRCToken
/// @notice HTS-compatible Fungible Token implementation for Plastic Recovery Credits.
///         1 PRC = 1 verified kilogram of ocean plastic removed.
///         Token has 3 decimal places → 0.001 PRC = 1 gram minimum granularity.
///         Provenance metadata for every batch is stored on-chain + anchored to HCS.
contract PRCToken {
    struct PRCBatch {
        string   attestationId;
        address  collectorId;
        address  stationId;
        string   zone;
        string   plasticType;
        uint256  weightGrams;
        uint256  payoutTinybar;
        uint256  hcsSequence;
        uint256  mintedAt;
        string   vintage;
    }

    struct RetirementCertificate {
        string    certId;
        address   company;
        string    companyName;
        string    reportRef;
        uint256   totalKgRetired;
        string[]  attestationIds;
        uint256   collectorsSupported;
        uint256   hbarPaidToCollectors;
        uint256   retiredAt;
        uint256   hcsSequence;
    }

    mapping(string => PRCBatch) public prcBatches;
    mapping(address => uint256) public balances;
    mapping(string => RetirementCertificate) public retirementCerts;

    address public admin;
    address public recoveryAgent;
    address public prcVault;
    CollectorRegistry public collectorRegistry;
    StationRegistry   public stationRegistry;

    uint256 public totalSupply;
    uint256 public totalRetired;
    uint256 private _certNonce;

    string[] public batchIds;
    string[] public retirementCertIds;

    event PRCMinted(
        string  indexed attestationId,
        address indexed collector,
        address indexed station,
        uint256 amount,
        string  plasticType,
        string  zone
    );

    event PRCRetired(
        address indexed company,
        string  companyName,
        uint256 amount,
        string  certId,
        string  reportRef
    );

    event PRCTransfer(address indexed from, address indexed to, uint256 amount);

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    modifier onlyAdminOrAgent() {
        require(msg.sender == admin || msg.sender == recoveryAgent, "Not authorized");
        _;
    }

    constructor(
        address _collectorRegistry,
        address _stationRegistry,
        address _prcVault
    ) {
        collectorRegistry = CollectorRegistry(_collectorRegistry);
        stationRegistry   = StationRegistry(_stationRegistry);
        prcVault          = _prcVault;
        admin             = msg.sender;
    }

    function setRecoveryAgent(address _agent) external onlyAdmin {
        recoveryAgent = _agent;
    }

    /// @notice Mint PRCs for a verified recovery attestation.
    ///         Called exclusively by the Recovery Agent after 5-check pipeline passes.
    function mintRecovery(
        string  memory _attestationId,
        address _collectorId,
        address _stationId,
        string  memory _plasticType,
        uint256 _weightGrams,
        string  memory _zoneId,
        uint256 _payoutTinybar,
        uint256 _hcsSequence
    ) external onlyAdminOrAgent {
        require(collectorRegistry.isCollectorActive(_collectorId), "Collector not active");
        require(stationRegistry.isStationActive(_stationId),       "Station not active");
        require(_weightGrams > 0,                                   "Invalid weight");
        require(bytes(prcBatches[_attestationId].attestationId).length == 0, "Batch already exists");

        // 1 gram = 1 token unit (3 decimal places → 1000 units = 1 PRC)
        uint256 prcAmount = _weightGrams;
        string memory vintage = _getVintage();

        prcBatches[_attestationId] = PRCBatch({
            attestationId:  _attestationId,
            collectorId:    _collectorId,
            stationId:      _stationId,
            zone:           _zoneId,
            plasticType:    _plasticType,
            weightGrams:    _weightGrams,
            payoutTinybar:  _payoutTinybar,
            hcsSequence:    _hcsSequence,
            mintedAt:       block.timestamp,
            vintage:        vintage
        });

        balances[prcVault] += prcAmount;
        totalSupply        += prcAmount;
        batchIds.push(_attestationId);

        emit PRCMinted(_attestationId, _collectorId, _stationId, prcAmount, _plasticType, _zoneId);
    }

    /// @notice Retire (burn) PRCs — called by corporate buyers to claim offset credit.
    ///         Mints a Retirement Certificate and anchors to HCS.
    function retire(
        uint256 _amount,
        string  memory _companyName,
        string  memory _reportRef
    ) external returns (string memory certId) {
        require(balances[msg.sender] >= _amount, "Insufficient PRC balance");

        certId = _generateCertId(_companyName);

        balances[msg.sender] -= _amount;
        totalRetired         += _amount;

        retirementCerts[certId] = RetirementCertificate({
            certId:               certId,
            company:              msg.sender,
            companyName:          _companyName,
            reportRef:            _reportRef,
            totalKgRetired:       _amount / 1000, // grams → kg
            attestationIds:       new string[](0),
            collectorsSupported:  0,
            hbarPaidToCollectors: 0,
            retiredAt:            block.timestamp,
            hcsSequence:          0 // Set by off-chain HCS anchoring
        });

        retirementCertIds.push(certId);

        emit PRCRetired(msg.sender, _companyName, _amount, certId, _reportRef);
        return certId;
    }

    function transfer(address _to, uint256 _amount) external {
        require(balances[msg.sender] >= _amount, "Insufficient balance");
        balances[msg.sender] -= _amount;
        balances[_to]        += _amount;
        emit PRCTransfer(msg.sender, _to, _amount);
    }

    function getBalance(address _account) external view returns (uint256) {
        return balances[_account];
    }

    function getAvailablePRCs() external view returns (uint256) {
        return balances[prcVault];
    }

    function getPRCBatch(string memory _attestationId) external view returns (PRCBatch memory) {
        return prcBatches[_attestationId];
    }

    function getRetirementCert(string memory _certId) external view returns (RetirementCertificate memory) {
        return retirementCerts[_certId];
    }

    function getBatchCount() external view returns (uint256) {
        return batchIds.length;
    }

    function getRetirementCount() external view returns (uint256) {
        return retirementCertIds.length;
    }

    // ─── Internal helpers ─────────────────────────────────────────────────────

    function _getVintage() internal view returns (string memory) {
        // Derive year from block.timestamp (seconds since Unix epoch)
        uint256 year = 1970 + block.timestamp / 365.25 days;
        return _uint2str(year);
    }

    /// @dev Generate a unique certificate ID:  PC-{YEAR}-CORP-{NONCE:04}
    function _generateCertId(string memory /*_companyName*/) internal returns (string memory) {
        _certNonce++;
        uint256 year = 1970 + block.timestamp / 365.25 days;
        return string(
            abi.encodePacked(
                "PC-",
                _uint2str(year),
                "-CORP-",
                _pad4(_certNonce)
            )
        );
    }

    function _uint2str(uint256 _i) internal pure returns (string memory) {
        if (_i == 0) return "0";
        uint256 j = _i;
        uint256 len;
        while (j != 0) { len++; j /= 10; }
        bytes memory bstr = new bytes(len);
        uint256 k = len;
        while (_i != 0) { k--; bstr[k] = bytes1(uint8(48 + _i % 10)); _i /= 10; }
        return string(bstr);
    }

    function _pad4(uint256 _n) internal pure returns (string memory) {
        string memory s = _uint2str(_n);
        bytes memory b = bytes(s);
        if (b.length >= 4) return s;
        bytes memory padded = new bytes(4);
        for (uint256 i = 0; i < 4 - b.length; i++) padded[i] = "0";
        for (uint256 i = 0; i < b.length; i++) padded[4 - b.length + i] = b[i];
        return string(padded);
    }
}

